import os
import urllib.request
from google.cloud import storage
import joblib

MODEL_ENV_VAR = "MODEL_PATH"
BUCKET_NAME = "your-bucket-name"

def get_latest_model_version(blob_prefix):
    client = storage.Client()
    blobs = client.list_blobs(BUCKET_NAME, prefix=blob_prefix)
    versions = [blob.name for blob in blobs if blob.name.endswith(".pkl")]
    return max(versions) if versions else None

def download_model():
    model_path = os.getenv(MODEL_ENV_VAR)
    latest_version = get_latest_model_version(f"{BUCKET_NAME}/{model_path}")
    if latest_version:
        url = f"gs://{BUCKET_NAME}/{latest_version}"
        print(f"Downloading model from {url}")
        urllib.request.urlretrieve(url, latest_version)
        print("Model downloaded successfully.")
    else:
        print(f"No models found in bucket for path '{model_path}'")

def load_model():
    model_path = os.getenv(MODEL_ENV_VAR)
    if not os.path.exists(model_path):
        download_model()
    return joblib.load(os.getenv(MODEL_ENV_VAR))

if __name__ == "__main__":
    loaded_model = load_model()
